sql:
SELECT COUNT(student_id) AS total_csci_students
FROM students
WHERE major = 'CSCI';

SELECT dept_name 
FROM departments 
WHERE NOT EXISTS (SELECT 1 FROM courses WHERE courses.dept_id = departments.dept_id);

SELECT faculty_name, office_hours
FROM faculty_members
WHERE faculty_id IN (1, 0);

SELECT course_id, student_id, evaluation_date, evaluation_comments
FROM course_evaluations
WHERE evaluation_id = 0;

SELECT DISTINCT instructor_id 
FROM course_sections 
WHERE course_id IN (
    SELECT course_id 
    FROM prerequisites
);
